"""
This module contains the Board class to represent the 8x8 checkers board.
"""

class Piece:
    def __init__(self, color, is_king=False):
        self.color = color
        self.is_king = is_king

    def __str__(self):
        return 'K' if self.is_king else 'X' if self.color == 'white' else 'O'

class Board:
    def __init__(self):
        self.squares = [[None] * 8 for _ in range(8)]
        self.init_board()

    def init_board(self):
        for i in range(3):
            for j in range(0, 8, 2):
                self.squares[i][j] = Piece('white')
            for j in range(1, 8, 2):
                self.squares[7-i][j] = Piece('black')

    def display(self):
        print("   a b c d e f g h")
        for i, row in enumerate(self.squares):
            print(f"{8 - i} {str.join(' | ', ['' if sq is None else str(sq) for sq in row])}")

    def apply_move(self, move):
        from_pos = (int(move[1]), ord(move[0]) - ord('a'))
        to_pos = (int(move[4]), ord(move[3]) - ord('a'))
        piece = self.squares[from_pos[0]][from_pos[1]]
        if piece is not None and piece.color == 'white':
            if move[2] in ['x', '+'] and self.is_valid_capture(from_pos, to_pos):
                self.squares[from_pos[0]][from_pos[1]] = None
                self.squares[to_pos[0]][to_pos[1]] = Piece('white')
                return True
        return False

    def is_valid_capture(self, from_pos, to_pos):
        # Placeholder for capture logic
        return False
